#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        char str[N + 1];
        scanf("%s", str);
        int maxBlock = 0;
        int currBlock = 1;
        for (int i = 1; i < N; i++) {
            if (str[i] == str[i - 1]) {
                currBlock++;
            } else {
                maxBlock = (maxBlock > currBlock) ? maxBlock : currBlock;
                currBlock = 1;
            }
        }
        maxBlock = (maxBlock > currBlock) ? maxBlock : currBlock;
        int changes = 0;
        for (int i = 0; i < N; i++) {
            if (str[i] == '0') {
                changes++;
            }
        }
        if (changes <= K) {
            printf("1\n");
        } else {
            printf("%d\n", (maxBlock + K - 1) / K);
        }
    }
    return 0;
}

