import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            String str = sc.next();
            int maxBlock = 0;
            int currBlock = 1;
            for (int i = 1; i < N; i++) {
                if (str.charAt(i) == str.charAt(i - 1)) {
                    currBlock++;
                } else {
                    maxBlock = Math.max(maxBlock, currBlock);
                    currBlock = 1;
                }
            }
            maxBlock = Math.max(maxBlock, currBlock);
            int changes = 0;
            for (int i = 0; i < N; i++) {
                if (str.charAt(i) == '0') {
                    changes++;
                }
            }
            if (changes <= K) {
                System.out.println(1);
            } else {
                System.out.println((maxBlock + K - 1) / K);
            }
        }
    }
}

